            double dist = 0;
            for (int i = 0; i < N; i++) {
                double expected = sorted_degrees[k][i] * (1.0 - 2.0 * eps) + (N - 1) * eps;
                double diff = h_degrees[i] - expected;
                dist += diff * diff;
            }
            if (dist < best_dist) {
                best_dist = dist;
                best_k = k;
            }
        }

        std::cout << best_k << "\n";
        std::cout.flush();
    }

    return 0;
}
