    int M;
    double eps;
    std::cin >> M >> eps;

    int N;
    if (eps < 1e-9) {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        N = bits_needed + 1;
        N = std::max(4, std::min(100, N));
    } else {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        int N_min_thresh = bits_needed + 1;

        double noise_factor = eps * (1.0 - eps);
        double C = 4.0;
        int N_noise = (int)std::ceil(C * C * M * noise_factor) + 1;
        N = std::max(N_min_thresh, N_noise);
        int N_strict = (int)std::ceil(9.0 * M * noise_factor) + 1;
        N = std::max(N, N_strict);
        N = std::max(4, std::min(100, N));
    }

    int L = N * (N - 1) / 2;
    std::cout << N << "\n";

    std::vector<std::vector<int>> chosen_degree_seqs(M);
    std::vector<std::string> chosen_strings(M);

    auto build_threshold_graph_from_bits = [&](const std::vector<bool>& bits) -> std::pair<std::vector<int>, std::string> {
        std::vector<int> deg(N, 0);
        std::string s(L, '0');

        for (int i = 1; i < N; i++) {
            if (bits[i - 1]) {
                for (int j = 0; j < i; j++) {
                    deg[i]++;
                    deg[j]++;
                    int pos = j * N - j * (j + 1) / 2 + (i - j - 1);
                    s[pos] = '1';
                }
            }
        }

        std::vector<int> sorted_deg = deg;
        std::sort(sorted_deg.begin(), sorted_deg.end());
        return {sorted_deg, s};
    };

    auto build_threshold_graph_from_code = [&](int code) -> std::pair<std::vector<int>, std::string> {
        std::vector<bool> bits(N - 1);
        for (int i = 0; i < N - 1; i++) bits[i] = (code >> i) & 1;
        return build_threshold_graph_from_bits(bits);
    };

    if (N <= 15) {
        int total = 1 << (N - 1);
        std::vector<std::vector<int>> all_deg_seqs(total);
        for (int c = 0; c < total; c++) {
            auto [ds, _] = build_threshold_graph_from_code(c);
            all_deg_seqs[c] = ds;
        }

        std::vector<int> selected;
        std::vector<double> min_d(total, 1e18);
        std::vector<bool> used(total, false);

        selected.push_back(0);
        used[0] = true;
        for (int c = 0; c < total; c++) {
            double d = 0;
            for (int i = 0; i < N; i++) { double x = all_deg_seqs[c][i]; d += x * x; }
            min_d[c] = d;
        }

        while ((int)selected.size() < M && (int)selected.size() < total) {
            int best_c = -1;
            double best = -1;
            for (int c = 0; c < total; c++) {
                if (!used[c] && min_d[c] > best) { best = min_d[c]; best_c = c; }
            }
            if (best_c == -1) break;
            selected.push_back(best_c);
            used[best_c] = true;
            for (int c = 0; c < total; c++) {
                if (used[c]) continue;
                double d = 0;
                for (int i = 0; i < N; i++) {
                    double diff = all_deg_seqs[c][i] - all_deg_seqs[best_c][i];
                    d += diff * diff;
                }
                min_d[c] = std::min(min_d[c], d);
            }
        }
        while ((int)selected.size() < M) selected.push_back(selected[0]);

        for (int k = 0; k < M; k++) {
            auto [ds, s] = build_threshold_graph_from_code(selected[k]);
            chosen_degree_seqs[k] = ds;
            chosen_strings[k] = s;
        }
