#include <cmath>
#include <chrono>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // N selection: With full hamming distance matching (L bits of info),
    // we can use smaller N than degree-sequence-only matching (N bits).
    // Signal: hamming distance between correct G and wrong G ~ d_edit * (1-2*eps)
    // Noise std: ~ sqrt(L * eps * (1-eps)) where L = N*(N-1)/2
    // But vertex alignment is imperfect → effective signal reduced
    //
    // For moderate eps, alignment quality is good enough that hamming distance
    // gives much better discrimination than degree sequence alone.
    // For high eps, alignment is poor → fall back to degree-seq-like accuracy.

    int N;
    if (eps < 1e-9) {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        N = bits_needed + 1;
        N = std::max(4, std::min(100, N));
    } else {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        int N_min_thresh = bits_needed + 1;

        // With hamming matching, we need less N than pure degree-seq matching.
        // Use a more moderate scaling:
        // SNR for hamming ~ sqrt(L) * (1-2*eps) / M
        // Need SNR > ~3 for reliable decoding
        // L = N*(N-1)/2 > (3*M/(1-2*eps))^2 * 2 ... but capped by alignment quality
        //
        // Empirical formula: combine degree-seq robustness requirement with hamming benefit
        double noise_factor = eps * (1.0 - eps);

        // Original (degree-seq only): N = 16*M*noise_factor + 1
        // With hamming: can reduce by factor ~2-3 for moderate eps
        double reduction = 1.0;
        if (eps <= 0.1) reduction = 0.4;
        else if (eps <= 0.2) reduction = 0.5;
        else if (eps <= 0.3) reduction = 0.7;
        else reduction = 0.85;

        int N_noise = (int)std::ceil(16.0 * M * noise_factor * reduction) + 1;
        N = std::max(N_min_thresh, N_noise);
        N = std::max(4, std::min(100, N));
    }

    int L = N * (N - 1) / 2;
    std::cout << N << "\n";

    // Build threshold graphs and store both edge strings and degree-sorted orderings
    std::vector<std::vector<int>> chosen_degree_seqs(M);
    std::vector<std::string> chosen_strings(M);
    // For each G_k, store the permutation that sorts vertices by degree (ascending)
    std::vector<std::vector<int>> chosen_degree_order(M);
    // Store the edge string in degree-sorted vertex order for hamming comparison
    std::vector<std::string> chosen_sorted_strings(M);

    auto build_threshold_graph_from_bits = [&](const std::vector<bool>& bits)
        -> std::tuple<std::vector<int>, std::string, std::vector<int>, std::string> {
        std::vector<int> deg(N, 0);
        std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

        for (int i = 1; i < N; i++) {
            if (bits[i - 1]) {
                for (int j = 0; j < i; j++) {
                    deg[i]++;
                    deg[j]++;
                    adj[i][j] = adj[j][i] = true;
                }
            }
        }

        // Original edge string
        std::string s(L, '0');
        int pos = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (adj[i][j]) s[pos] = '1';
                pos++;
            }
        }

        // Sort vertices by degree (ascending), breaking ties by original index
        std::vector<int> order(N);
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] < deg[b] || (deg[a] == deg[b] && a < b);
        });

        // Sorted degree sequence
        std::vector<int> sorted_deg(N);
        for (int i = 0; i < N; i++) sorted_deg[i] = deg[order[i]];

