        std::string sorted_s(L, '0');
        pos = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (adj[order[i]][order[j]]) sorted_s[pos] = '1';
                pos++;
            }
        }

        return {sorted_deg, s, order, sorted_s};
    };

    auto build_threshold_graph_from_code = [&](int code) {
        std::vector<bool> bits(N - 1);
        for (int i = 0; i < N - 1; i++) bits[i] = (code >> i) & 1;
        return build_threshold_graph_from_bits(bits);
    };

