        candidate_bits.push_back(std::vector<bool>(N - 1, true));

        // Prefix dominators
        for (int nd = 0; nd <= N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            for (int p = 0; p < nd; p++) bits[p] = true;
            candidate_bits.push_back(bits);
        }
        // Suffix dominators
        for (int nd = 0; nd <= N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            for (int p = N - 2; p >= 0 && p >= N - 1 - nd; p--) bits[p] = true;
            candidate_bits.push_back(bits);
        }
        // Interleaved
        for (int nd = 1; nd < N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            double step = (double)(N - 1) / nd;
            for (int p = 0; p < nd; p++) {
                int pos = (int)(p * step);
                if (pos < N - 1) bits[pos] = true;
            }
            candidate_bits.push_back(bits);
        }

        // Random candidates with various dominator counts
        for (int nd = 0; nd <= N - 1; nd++) {
            int variants = num_candidates / (N + 1);
            for (int v = 0; v < variants; v++) {
                std::vector<bool> bits(N - 1, false);
                std::vector<int> positions(N - 1);
                std::iota(positions.begin(), positions.end(), 0);
                std::shuffle(positions.begin(), positions.end(), rng);
                for (int p = 0; p < nd; p++) bits[positions[p]] = true;
                candidate_bits.push_back(bits);
            }
        }

        int total_cands = candidate_bits.size();
        candidate_deg_seqs.resize(total_cands);
        for (int i = 0; i < total_cands; i++) {
            auto [ds, _] = build_threshold_graph_from_bits(candidate_bits[i]);
            candidate_deg_seqs[i] = ds;
        }

        std::vector<double> min_d(total_cands, 1e18);
        std::vector<bool> used(total_cands, false);
        std::vector<int> selected;

        selected.push_back(0);
        used[0] = true;
        for (int c = 0; c < total_cands; c++) {
            double d = 0;
            for (int i = 0; i < N; i++) {
                double diff = candidate_deg_seqs[c][i] - candidate_deg_seqs[0][i];
                d += diff * diff;
            }
            min_d[c] = d;
        }

        while ((int)selected.size() < M) {
            int best_c = -1;
            double best = -1;
            for (int c = 0; c < total_cands; c++) {
                if (!used[c] && min_d[c] > best) { best = min_d[c]; best_c = c; }
            }
            if (best_c == -1) break;
            selected.push_back(best_c);
            used[best_c] = true;
            for (int c = 0; c < total_cands; c++) {
                if (used[c]) continue;
                double d = 0;
                for (int i = 0; i < N; i++) {
                    double diff = candidate_deg_seqs[c][i] - candidate_deg_seqs[best_c][i];
                    d += diff * diff;
                }
                min_d[c] = std::min(min_d[c], d);
            }
        }
        while ((int)selected.size() < M) selected.push_back(selected[0]);

        for (int k = 0; k < M; k++) {
            auto [ds, s] = build_threshold_graph_from_bits(candidate_bits[selected[k]]);
            chosen_degree_seqs[k] = ds;
            chosen_strings[k] = s;
        }
    }

    for (int k = 0; k < M; k++) {
        std::cout << chosen_strings[k] << "\n";
    }
    std::cout.flush();

    for (int q = 0; q < 100; q++) {
        std::string h_str;
        std::cin >> h_str;

        std::vector<int> h_degrees(N, 0);
        int idx = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (h_str[idx] == '1') {
                    h_degrees[i]++;
                    h_degrees[j]++;
                }
                idx++;
            }
        }
        std::sort(h_degrees.begin(), h_degrees.end());

        int best_k = 0;
        double best_dist = 1e18;
        for (int k = 0; k < M; k++) {
            double dist = 0;
            for (int i = 0; i < N; i++) {
                double expected = chosen_degree_seqs[k][i] * (1.0 - 2.0 * eps) + (N - 1.0) * eps;
                double diff = h_degrees[i] - expected;
                dist += diff * diff;
            }
            if (dist < best_dist) {
                best_dist = dist;
                best_k = k;
            }
        }

        std::cout << best_k << "\n";
        std::cout.flush();
    }

