#include <random>
#include <cmath>
#include <chrono>
#include <tuple>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // N selection: With full hamming distance matching (L bits of info),
    // we can use smaller N than degree-sequence-only matching (N bits).
    // Signal: hamming distance between correct G and wrong G ~ d_edit * (1-2*eps)
    // Noise std: ~ sqrt(L * eps * (1-eps)) where L = N*(N-1)/2
    // But vertex alignment is imperfect → effective signal reduced
    //
    // For moderate eps, alignment quality is good enough that hamming distance
    // gives much better discrimination than degree sequence alone.
    // For high eps, alignment is poor → fall back to degree-seq-like accuracy.

    int N;
    if (eps < 1e-9) {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        N = bits_needed + 1;
        N = std::max(4, std::min(100, N));
    } else {
        int bits_needed = 0;
        int temp = M - 1;
        while (temp > 0) { bits_needed++; temp >>= 1; }
        int N_min_thresh = bits_needed + 1;

        // With hamming matching, we need less N than pure degree-seq matching.
        // Use a more moderate scaling:
        // SNR for hamming ~ sqrt(L) * (1-2*eps) / M
        // Need SNR > ~3 for reliable decoding
        // L = N*(N-1)/2 > (3*M/(1-2*eps))^2 * 2 ... but capped by alignment quality
        //
        // Empirical formula: combine degree-seq robustness requirement with hamming benefit
        double noise_factor = eps * (1.0 - eps);

        // Original (degree-seq only): N = 16*M*noise_factor + 1
        // With hamming: can reduce by factor ~2-3 for moderate eps
        double reduction = 1.0;
        if (eps <= 0.1) reduction = 0.4;
        else if (eps <= 0.2) reduction = 0.5;
        else if (eps <= 0.3) reduction = 0.7;
        else reduction = 0.85;

        int N_noise = (int)std::ceil(16.0 * M * noise_factor * reduction) + 1;
        N = std::max(N_min_thresh, N_noise);
        N = std::max(4, std::min(100, N));
    }

    int L = N * (N - 1) / 2;
    std::cout << N << "\n";

    // Build threshold graphs and store both edge strings and degree-sorted orderings
    std::vector<std::vector<int>> chosen_degree_seqs(M);
    std::vector<std::string> chosen_strings(M);
    // For each G_k, store the permutation that sorts vertices by degree (ascending)
    std::vector<std::vector<int>> chosen_degree_order(M);
    // Store the edge string in degree-sorted vertex order for hamming comparison
    std::vector<std::string> chosen_sorted_strings(M);

    auto build_threshold_graph_from_bits = [&](const std::vector<bool>& bits)
        -> std::tuple<std::vector<int>, std::string, std::vector<int>, std::string> {
        std::vector<int> deg(N, 0);
        std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

        for (int i = 1; i < N; i++) {
            if (bits[i - 1]) {
                for (int j = 0; j < i; j++) {
                    deg[i]++;
                    deg[j]++;
                    adj[i][j] = adj[j][i] = true;
                }
            }
        }

        // Original edge string
        std::string s(L, '0');
        int pos = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (adj[i][j]) s[pos] = '1';
                pos++;
            }
        }

        // Sort vertices by degree (ascending), breaking ties by original index
        std::vector<int> order(N);
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] < deg[b] || (deg[a] == deg[b] && a < b);
        });

        // Sorted degree sequence
        std::vector<int> sorted_deg(N);
        for (int i = 0; i < N; i++) sorted_deg[i] = deg[order[i]];

        // Edge string in sorted order
        std::string sorted_s(L, '0');
        pos = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (adj[order[i]][order[j]]) sorted_s[pos] = '1';
                pos++;
            }
        }

        return {sorted_deg, s, order, sorted_s};
    };

    auto build_threshold_graph_from_code = [&](int code) {
        std::vector<bool> bits(N - 1);
        for (int i = 0; i < N - 1; i++) bits[i] = (code >> i) & 1;
        return build_threshold_graph_from_bits(bits);
    };

    // Graph selection: greedy max-separation on sorted degree sequences
    if (N <= 15) {
        int total = 1 << (N - 1);
        std::vector<std::vector<int>> all_deg_seqs(total);
        for (int c = 0; c < total; c++) {
            auto [ds, s, order, ss] = build_threshold_graph_from_code(c);
            all_deg_seqs[c] = ds;
        }

        std::vector<int> selected;
        std::vector<double> min_d(total, 1e18);
        std::vector<bool> used(total, false);

        selected.push_back(0);
        used[0] = true;
        for (int c = 0; c < total; c++) {
            double d = 0;
            for (int i = 0; i < N; i++) { double x = all_deg_seqs[c][i]; d += x * x; }
            min_d[c] = d;
        }

        while ((int)selected.size() < M && (int)selected.size() < total) {
            int best_c = -1;
            double best = -1;
            for (int c = 0; c < total; c++) {
                if (!used[c] && min_d[c] > best) { best = min_d[c]; best_c = c; }
            }
            if (best_c == -1) break;
            selected.push_back(best_c);
            used[best_c] = true;
            for (int c = 0; c < total; c++) {
                if (used[c]) continue;
                double d = 0;
                for (int i = 0; i < N; i++) {
                    double diff = all_deg_seqs[c][i] - all_deg_seqs[best_c][i];
                    d += diff * diff;
                }
                min_d[c] = std::min(min_d[c], d);
            }
        }
        while ((int)selected.size() < M) selected.push_back(selected[0]);

        for (int k = 0; k < M; k++) {
            auto [ds, s, order, ss] = build_threshold_graph_from_code(selected[k]);
            chosen_degree_seqs[k] = ds;
            chosen_strings[k] = s;
            chosen_degree_order[k] = order;
            chosen_sorted_strings[k] = ss;
        }
    } else {
        std::mt19937 rng(42 + M * 100 + N * 7);
        int num_candidates = std::min(10000, std::max(2000, 50 * M));

        std::vector<std::vector<bool>> candidate_bits;
        std::vector<std::vector<int>> candidate_deg_seqs;

        candidate_bits.push_back(std::vector<bool>(N - 1, false));
        candidate_bits.push_back(std::vector<bool>(N - 1, true));

        for (int nd = 0; nd <= N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            for (int p = 0; p < nd; p++) bits[p] = true;
            candidate_bits.push_back(bits);
        }
        for (int nd = 0; nd <= N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            for (int p = N - 2; p >= 0 && p >= N - 1 - nd; p--) bits[p] = true;
            candidate_bits.push_back(bits);
        }
        for (int nd = 1; nd < N - 1; nd++) {
            std::vector<bool> bits(N - 1, false);
            double step = (double)(N - 1) / nd;
            for (int p = 0; p < nd; p++) {
                int pos2 = (int)(p * step);
                if (pos2 < N - 1) bits[pos2] = true;
            }
            candidate_bits.push_back(bits);
        }

        for (int nd = 0; nd <= N - 1; nd++) {
            int variants = num_candidates / (N + 1);
            for (int v = 0; v < variants; v++) {
                std::vector<bool> bits(N - 1, false);
                std::vector<int> positions(N - 1);
                std::iota(positions.begin(), positions.end(), 0);
                std::shuffle(positions.begin(), positions.end(), rng);
                for (int p = 0; p < nd; p++) bits[positions[p]] = true;
                candidate_bits.push_back(bits);
            }
        }

        int total_cands = candidate_bits.size();
        candidate_deg_seqs.resize(total_cands);
        for (int i = 0; i < total_cands; i++) {
            auto [ds, s, order, ss] = build_threshold_graph_from_bits(candidate_bits[i]);
            candidate_deg_seqs[i] = ds;
        }

        std::vector<double> min_d(total_cands, 1e18);
        std::vector<bool> used(total_cands, false);
        std::vector<int> selected;

        selected.push_back(0);
        used[0] = true;
        for (int c = 0; c < total_cands; c++) {
            double d = 0;
            for (int i = 0; i < N; i++) {
                double diff = candidate_deg_seqs[c][i] - candidate_deg_seqs[0][i];
                d += diff * diff;
            }
            min_d[c] = d;
        }

        while ((int)selected.size() < M) {
            int best_c = -1;
            double best = -1;
            for (int c = 0; c < total_cands; c++) {
                if (!used[c] && min_d[c] > best) { best = min_d[c]; best_c = c; }
            }
            if (best_c == -1) break;
            selected.push_back(best_c);
            used[best_c] = true;
            for (int c = 0; c < total_cands; c++) {
                if (used[c]) continue;
                double d = 0;
                for (int i = 0; i < N; i++) {
                    double diff = candidate_deg_seqs[c][i] - candidate_deg_seqs[best_c][i];
                    d += diff * diff;
                }
                min_d[c] = std::min(min_d[c], d);
            }
        }
        while ((int)selected.size() < M) selected.push_back(selected[0]);

        for (int k = 0; k < M; k++) {
            auto [ds, s, order, ss] = build_threshold_graph_from_bits(candidate_bits[selected[k]]);
            chosen_degree_seqs[k] = ds;
            chosen_strings[k] = s;
            chosen_degree_order[k] = order;
            chosen_sorted_strings[k] = ss;
        }
    }

    for (int k = 0; k < M; k++) {
        std::cout << chosen_strings[k] << "\n";
    }
    std::cout.flush();

    // Decoding: For each query H, use a hybrid approach:
    // 1. Sort H's vertices by degree (ascending)
    // 2. Compute hamming distance between H's sorted edge string and each G_k's sorted edge string
    // 3. Also compute degree-sequence L2 distance
    // 4. Use weighted combination, or just hamming (which subsumes degree info)
    //
    // The hamming distance after alignment is a stronger signal than degree-seq L2
    // because it uses L = N(N-1)/2 bits vs N values.

    for (int q = 0; q < 100; q++) {
        std::string h_str;
        std::cin >> h_str;

        // Parse H into adjacency
        std::vector<std::vector<bool>> h_adj(N, std::vector<bool>(N, false));
        std::vector<int> h_deg(N, 0);
        int idx = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (h_str[idx] == '1') {
                    h_adj[i][j] = h_adj[j][i] = true;
                    h_deg[i]++;
                    h_deg[j]++;
                }
                idx++;
            }
        }

        // Sort H's vertices by degree
        std::vector<int> h_order(N);
        std::iota(h_order.begin(), h_order.end(), 0);
        std::sort(h_order.begin(), h_order.end(), [&](int a, int b) {
            return h_deg[a] < h_deg[b] || (h_deg[a] == h_deg[b] && a < b);
        });

        // Compute H's edge string in sorted vertex order
        std::string h_sorted_str(L, '0');
        int pos = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (h_adj[h_order[i]][h_order[j]]) h_sorted_str[pos] = '1';
                pos++;
            }
        }

        // Compute sorted degree sequence
        std::vector<int> h_sorted_deg(N);
        for (int i = 0; i < N; i++) h_sorted_deg[i] = h_deg[h_order[i]];

        // Match using weighted combination of hamming distance and degree-seq L2
        int best_k = 0;
        double best_score = 1e18;

        for (int k = 0; k < M; k++) {
            // Hamming distance on sorted edge strings
            int hamming = 0;
            for (int i = 0; i < L; i++) {
                if (h_sorted_str[i] != chosen_sorted_strings[k][i]) hamming++;
            }

            // Degree sequence L2 distance (noise-adjusted)
            double deg_dist = 0;
            for (int i = 0; i < N; i++) {
                double expected = chosen_degree_seqs[k][i] * (1.0 - 2.0 * eps) + (N - 1.0) * eps;
                double diff = h_sorted_deg[i] - expected;
                deg_dist += diff * diff;
            }

            // Combined score: use hamming as primary (it's more informative)
            // Weight degree-seq distance as a regularizer for when alignment is poor
            // Hamming expected under correct match with perfect alignment: L * eps
            // Hamming expected under wrong match: L * eps + d_edit * (1 - 2*eps)
            // Degree-seq L2 expected under correct match: N * (N-1) * eps * (1-eps)
            //
            // Normalize both to unit variance and combine:
            double hamming_norm = (double)hamming;
            double deg_norm = deg_dist;

            // For high eps, alignment is unreliable → weight degree more
            // For low eps, alignment is good → weight hamming more
            double alpha = 1.0 - eps * 1.5; // weight on hamming (1.0 for eps=0, ~0.4 for eps=0.4)
            alpha = std::max(0.2, std::min(1.0, alpha));

            // Normalize: hamming is in [0, L], deg_dist is in [0, N*(N-1)^2]
            // Scale hamming to be comparable to deg_dist
            double combined = alpha * hamming_norm + (1.0 - alpha) * deg_norm / (N - 1.0 + 1e-9);

            if (combined < best_score) {
                best_score = combined;
                best_k = k;
            }
        }

        std::cout << best_k << "\n";
        std::cout.flush();
    }

    return 0;
}
